import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface DeliveryProgress {
  stage: string;
  completed: boolean;
}

interface OrderTrackingData {
  orderId: string;
  currentStatus: string;
  estimatedDelivery: string;
  deliveryProgress: DeliveryProgress[];
  progressChart: number[];
}

export default function Widget() {
  const orderData = response.data as OrderTrackingData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Order ID
            </Typography>
            <Typography variant="h6" fontWeight={500} sx={{ mb: 1 }}>
              {orderData.orderId}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Status
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#FF5722', mb: 1 }}>
              {orderData.currentStatus}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Delivery
            </Typography>
            <Typography variant="body1" fontWeight={500}>
              {new Date(orderData.estimatedDelivery).toLocaleString()}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Delivery Progress
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {orderData.deliveryProgress.map((progress, index) => (
                <Chip
                  key={index}
                  label={progress.stage}
                  sx={{
                    fontSize: '11px',
                    px: 1,
                    py: 0.5,
                    bgcolor: progress.completed ? '#FFC107' : '#F5F5F5',
                    color: progress.completed ? '#FFFFFF' : '#BDBDBD',
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 100 }}>
            <LineChart
              series={[
                {
                  data: orderData.progressChart,
                  color: '#FF5722',
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: orderData.deliveryProgress.map((_, i) => i),
                  hide: true,
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
